import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { PieChart } from '@mui/x-charts';
import response from './response.json';

interface Pollutant {
  name: string;
  value: number;
  unit: string;
}

interface AirQualityData {
  location: string;
  currentAQI: {
    value: number;
    category: string;
  };
  pollutants: Pollutant[];
}

export default function Widget() {
  const airQualityData = response.data as AirQualityData;
  const { location, currentAQI, pollutants } = airQualityData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" color="text.secondary">
              {location}
            </Typography>
            <Typography variant="h4" fontWeight={700} sx={{ color: '#FF5722' }}>
              AQI: {currentAQI.value}
            </Typography>
            <Typography variant="caption" sx={{ color: '#FF5722' }}>
              {currentAQI.category}
            </Typography>
          </Box>

          <Box sx={{ width: '100%', height: 150 }}>
            <PieChart
              height={150}
              series={[
                {
                  data: pollutants.map(p => ({ id: p.name, value: p.value })),
                  colorBy: 'id',
                  colors: ['#4CAF50', '#FF5722', '#2196F3'],
                },
              ]}
              sx={{
                '& .MuiPieSlice-root': {
                  strokeWidth: 1,
                },
              }}
            />
          </Box>

          <Stack direction="row" spacing={1}>
            {pollutants.map(pollutant => (
              <Chip
                key={pollutant.name}
                label={`${pollutant.name}: ${pollutant.value}${pollutant.unit}`}
                sx={{ fontSize: '11px', px: 1, py: 0.5 }}
              />
            ))}
          </Stack>
        </Stack>
      </CardContent>
    </Card>
  );
}
